var f = this, id = f.get_id(), v = f._language == 'v', m1 = f.getItemValue('tien_tu'), m2 = f.getItemValue('tien_den');
if (m2 != 0 && m1 > m2) {
  var e = 'tien_den';
  f._checked = false;
  $func.hideWait(id);
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), f.getItem(e).field.Label), String.format('$find(\'{0}\').getItem(\'{1}\').focus()', id, e));
}

script.text:

function init$Form$&Controller;(f) {setDefaultValue$Form$&Controller;(f);}
function active$Form$&Controller;(f) {
  f.add_onResponseComplete(on$Form$&Controller;$ResponseComplete);
  setObjectFocus(f);
}
function scatter$Form$&Controller;(f) {
  setDefaultValue$Form$&Controller;(f);
  setObjectFocus(f);
}
function close$Form$&Controller;(f) {try {f.remove_onResponseComplete(on$Form$&Controller;$ResponseComplete)} catch (ex) {}}
function on$Form$&Controller;$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      break;
    default:
      break;
  }
}
function setDefaultValue$Form$&Controller;(f) {
  f._$active = null;
  var g = f.grid, type = (g._approvalType == '1');
  if (f._action == 'New') f.setItemValues('loai_duyet, ma_kieu, ten_kieu%l', [g._approvalType, g._approvalCategory, g._approvalCategoryName]);
  var a = ['dvcs', 'ma_bp', 'ma_md', 'nh_kh1', 'nh_kh2', 'nh_kh3', 'tien_tu', 'tien_den', 'ma_nt'], n = 6;
  for (var i = 0; i < a.length; i++) {
    var k = (i > n ? n : i), c = a[i], v = g._$u[k];
    setObjectFormHidden(f, c, v);
    if (i == 8 || i < n) setObjectAllowNulls(f, c, v);
    if (!f._$active && !v) f._$active = c;
  }
}
/* <flatten type="Javascript"> */
function setObjectFocus(f) {f.getItem(f._$active).focus();}
function setObjectAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = v
      grandNode = o.parentNode.parentNode;
      if (!v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else {
        Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
        Sys.UI.DomElement.removeCssClass(grandNode, f._id);
      }
    }
  }
}
function setObjectFormHidden(f, c, b) {if (b) {$common.setVisible(f.getItem(c).parentNode.parentNode.parentNode, false);}}
/* </flatten> */
